class Solution {
    public boolean isRationalEqual(String s, String t) {
        s = s.replace(".", "");
        t = t.replace(".", "");
        s = s.replace("(", "");
        t = t.replace(")", "");
        if (s.equals(t)) return true;
        int i = s.indexOf("(");
        int j = t.indexOf("(");
        if (i == -1 && j == -1) return false;
        if (i == -1) {
            s = s + "(" + s.substring(i + 1) + ")";
        }
        if (j == -1) {
            t = t + "(" + t.substring(j + 1) + ")";
        }
        s = s.replace("(", ".");
        t = t.replace("(", ".");
        return s.equals(t);
    }
}
